  ('pukao-e3452428-moex-00257', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依司法院釋字第499號解釋，下列何者非屬不得修憲予以變更之自由民主憲政秩序之內容？', '["國民主權原則", "保障人民基本權利", "權力分立與制衡", "地方自治團體的制度保障"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00258', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依憲法規定，憲法所保障之地方自治，不及於何層級之自治團體？', '["直轄市", "縣", "與縣同級的市", "鄉（鎮、市）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00259', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '有關鄉之敘述，下列何者正確？', '["鄉以內之編組為村", "鄉之行政機關為鄉政府", "鄉之立法機關為鄉議會", "鄉長為無給職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00260', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '縣政府為使該縣境內各鄉（鎮、市）能均衡發展，應酌予補助財力較差之鄉（鎮、市），其補助辦 法由何者訂定？', '["由行政院訂定並送立法院備查", "地方自治事項之中央主管機關", "該縣自行訂定", "由中央目的事業主管機關定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00261', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '地方自治條例與憲法、法律或基於法律授權之法規牴觸者，應如何處理？', '["由自治監督機關函告無效", "地方自治條例得優先適用", "交由司法機關仲裁", "由中央與地方自治團體進行協商解決"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00262', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '下列何者非屬地方行政機關訂定自治規則權限之依據？', '["依其法定職權", "依自治條例之授權", "依中央法規命令之授權", "依中央職權命令之授權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00263', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依平均地權條例第62條之1規定，重劃區內應行拆遷之土地改良物等，應予以補償，其補償數額由 直轄市或縣（市）政府查定之。下列敘述何者正確？', '["拆遷土地改良物之損失補償事務，因適用國家之土地徵收補償法制，非屬自治事項", "直轄市政府依上開規定辦理拆遷土地改良物損失補償事務，屬於地方制度法第18條所定其他依 法律賦予之自治事項", "直轄市政府依上開規定辦理拆遷土地改良物損失補償事務，係辦理上級機關委辦事項", "直轄市政府可另行制定拆遷土地改良物損失補償自治條例來訂定補償標準，但應報經行政院核 定後發布"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00264', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依地方制度法規定，關於地方行政首長之代理與補選，下列敘述何者錯誤？', '["鄉長辭職，應由副鄉長代理，若不能代理者，由縣政府派員代理", "直轄市長辭職者，原則上應自事實發生之日起3個月內完成補選", "縣長停職，而副縣長出缺或不能代理者，由內政部報請行政院派員代理", "直轄市長補選之當選人，其任期以補足該屆所遺任期為限，並視為一屆"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
